import React from "react";
import styled, { css } from "styled-components";
import { Link } from "react-router-dom";

/**
 * Button types
 * @typedef {"primary" | "secondary" | "tertiary"} ButtonVariant
 * @typedef {"small" | "medium" | "large"} ButtonSize
 */

/**
 * Button props interface
 * @typedef {Object} ButtonProps
 * @property {string} [className] - Additional CSS class
 * @property {React.ReactNode} children - Button content
 * @property {ButtonVariant} [variant="primary"] - Button variant
 * @property {ButtonSize} [size="medium"] - Button size
 * @property {boolean} [disabled=false] - Is button disabled
 * @property {string} [to] - Internal link path (uses React Router)
 * @property {string} [href] - External link URL
 * @property {React.MouseEventHandler} [onClick] - Click handler
 * @property {string} [type="button"] - Button type attribute
 */

/**
 * Meta-style Button component
 * @param {ButtonProps} props - Button properties
 * @returns {JSX.Element} Button component
 */
const Button = ({
  className,
  children,
  variant = "primary",
  size = "medium",
  disabled = false,
  to,
  href,
  onClick,
  type = "button",
  ...rest
}) => {
  // Determine which component to render based on props
  const ButtonComponent = to ? StyledLink : href ? StyledAnchor : StyledButton;

  return (
    <ButtonComponent
      className={className}
      variant={variant}
      size={size}
      disabled={disabled}
      to={to}
      href={href}
      onClick={onClick}
      type={type}
      {...rest}
    >
      {children}
    </ButtonComponent>
  );
};

// Common button styles
const buttonStyles = css`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-weight: 600;
  border-radius: 100px;
  transition: all 0.2s ease;
  cursor: pointer;
  text-decoration: none;
  position: relative;
  overflow: hidden;
  white-space: nowrap;

  // Use the focus-visible style to show outline only when keyboard focused
  &:focus-visible {
    outline: 2px solid var(--primary-color);
    outline-offset: 2px;
  }

  &:active {
    transform: translateY(1px);
  }

  // Variant styles
  ${props => {
    switch (props.variant) {
      case "primary":
        return css`
          background-color: var(--primary-color);
          color: white;
          border: none;

          &:hover:not(:disabled) {
            background-color: var(--secondary-color);
            box-shadow: 0 4px 16px rgba(0, 0, 0, 0.1);
          }

          &:active:not(:disabled) {
            background-color: var(--primary-color);
          }
        `;
      case "secondary":
        return css`
          background-color: white;
          color: var(--primary-color);
          border: 1px solid var(--border-color);

          &:hover:not(:disabled) {
            border-color: var(--primary-color);
            background-color: rgba(6, 104, 225, 0.05);
          }

          &:active:not(:disabled) {
            background-color: rgba(6, 104, 225, 0.1);
          }
        `;
      case "tertiary":
        return css`
          background-color: transparent;
          color: var(--primary-color);
          border: none;

          &:hover:not(:disabled) {
            background-color: rgba(6, 104, 225, 0.05);
          }

          &:active:not(:disabled) {
            background-color: rgba(6, 104, 225, 0.1);
          }
        `;
      default:
        return "";
    }
  }}

  // Size styles
  ${props => {
    switch (props.size) {
      case "small":
        return css`
          font-size: 14px;
          padding: 8px 16px;
          min-height: 32px;
        `;
      case "medium":
        return css`
          font-size: 16px;
          padding: 12px 24px;
          min-height: 40px;
        `;
      case "large":
        return css`
          font-size: 18px;
          padding: 16px 32px;
          min-height: 48px;
        `;
      default:
        return "";
    }
  }}

  // Disabled style
  ${props => props.disabled && css`
    opacity: 0.5;
    cursor: not-allowed;

    &:hover {
      transform: none;
      box-shadow: none;
    }
  `}
`;

// Styled components for different button types
const StyledButton = styled.button`
  ${buttonStyles}
`;

const StyledLink = styled(Link)`
  ${buttonStyles}
`;

const StyledAnchor = styled.a`
  ${buttonStyles}
`;

export default Button;
